sp_widget.client_script:
api.controller = function($window, $scope, spUtil,spModal) {
  var c = this;

  /* ================= INIT ================= */

  c.filtered           = [];
  c.filters = {
    businessUnit: '',
    year:         '',
    search:       ''
  };
  c.selectedQuota      = '';
  c.selectedQuotaLabel = '';
  c.quotaSearch        = '';
  c.quotaDisplayText   = '';
  c.filteredQuotas     = [];
  c.quotaDropOpen      = false;
  c.view               = 'main';

  /* ================= USER FILTER — SN-style condition builder ================= */

  c.userConditions    = [{ field: '', operator: 'contains', value: '', logic: 'AND' }];
  c.filteredUsers     = [];
  c.userFilterApplied = false;

  c.addCondition = function() {
    c.userConditions.push({ field: '', operator: 'contains', value: '', logic: 'AND' });
  };

  c.removeCondition = function(idx) {
    c.userConditions.splice(idx, 1);
    if (c.userConditions.length === 0) {
      c.addCondition();
    }
    if (c.userFilterApplied) c.runUserFilter();
  };

  c.onFieldChange = function(cond) {
    cond.operator = 'contains';
    cond.value    = '';
  };

  c._matchCond = function(user, cond) {
    if (!cond.field || !cond.value) return true;

    var fieldMap = {
      name:          user.name    || '',
      email:         user.email   || '',
      business_unit: user.segment || '',
      role:          user.role    || '',
      segment:       user.segment || ''
    };

    var fieldVal = (fieldMap[cond.field] || '').toLowerCase();
    var condVal  = (cond.value           || '').toLowerCase();

    if (cond.operator === 'is')          return fieldVal === condVal;
    if (cond.operator === 'starts_with') return fieldVal.indexOf(condVal) === 0;
    return fieldVal.indexOf(condVal) !== -1;
  };

  c.runUserFilter = function() {
    c.userFilterApplied = true;
    var all = c.data.users || [];

    var activeConds = c.userConditions.filter(function(cond) {
      return cond.field && cond.value;
    });

    if (!activeConds.length) {
      c.filteredUsers = all;
      return;
    }

    c.filteredUsers = all.filter(function(user) {
      var result = c._matchCond(user, activeConds[0]);
      for (var i = 1; i < activeConds.length; i++) {
        var prev  = activeConds[i - 1];
        var match = c._matchCond(user, activeConds[i]);
        if (prev.logic === 'OR') {
          result = result || match;
        } else {
          result = result && match;
        }
      }
      return result;
    });
  };

  c.clearUserFilter = function() {
    c.userConditions    = [{ field: '', operator: 'contains', value: '', logic: 'AND' }];
    c.userFilterApplied = false;
    c.filteredUsers     = c.data.users || [];
  };

  /* ================= FILTER LOGIC ================= */

  c.applyFilter = function() {
    var list = angular.copy(c.data.rows || []);

    if (c.filters.businessUnit) {
      list = list.filter(function(r) {
        return r.businessUnit === c.filters.businessUnit;
      });
    }

    if (c.filters.year) {
      list = list.filter(function(r) {
        return r.financialYear === c.filters.year;
      });
    }

    if (c.filters.search) {
      var s = c.filters.search.toLowerCase();
      list = list.filter(function(r) {
        return (r.user  && r.user.toLowerCase().indexOf(s)  !== -1) ||
               (r.quota && r.quota.toLowerCase().indexOf(s) !== -1);
      });
    }

    c.filtered = list;
  };

  /* ================= QUOTA COMBINED SEARCH + SELECT ================= */

  c.openQuotaDrop = function() {
    c.filteredQuotas   = c.data.quotas || [];
    c.quotaDisplayText = '';
    c.quotaSearch      = '';
    c.quotaDropOpen    = true;
  };

  c.onQuotaInputChange = function() {
    c.quotaSearch   = c.quotaDisplayText;
    c.quotaDropOpen = true;

    var all = c.data.quotas || [];

    if (!c.quotaSearch) {
      c.filteredQuotas = all;
      return;
    }

    var s = c.quotaSearch.toLowerCase();

    c.filteredQuotas = all.filter(function(q) {
      return (q.name          && q.name.toLowerCase().indexOf(s)            !== -1) ||
             (q.business_unit && q.business_unit.toLowerCase().indexOf(s)   !== -1) ||
             (q.financial_year && q.financial_year.toLowerCase().indexOf(s) !== -1);
    });
  };

  c.filterQuotas = function() {
    c.onQuotaInputChange();
  };

  c.pickQuota = function(q) {
    c.selectedQuota      = q.sys_id;
    c.selectedQuotaLabel = q.name +
      (q.business_unit  ? ' | ' + q.business_unit  : '') +
      (q.financial_year ? ' | ' + q.financial_year : '');
    c.quotaDisplayText = c.selectedQuotaLabel;
    c.quotaSearch      = '';
    c.filteredQuotas   = c.data.quotas || [];
    c.quotaDropOpen    = false;
  };

  c.clearQuotaSelection = function() {
    c.selectedQuota      = '';
    c.selectedQuotaLabel = '';
    c.quotaSearch        = '';
    c.quotaDisplayText   = '';
    c.filteredQuotas     = c.data.quotas || [];
    c.quotaDropOpen      = false;
  };

  angular.element(document).on('click', function(e) {
    if (!angular.element(e.target).closest('.qa-quota-search-wrap').length) {
      $scope.$apply(function() {
        c.quotaDropOpen = false;
      });
    }
  });

  /* ================= PAGE NAVIGATION ================= */

	c.goBack = function() {
    $window.history.back();
  };

  /* ================= RESET FORM ================= */

  c.resetForm = function() {
    c.selectedQuota      = '';
    c.selectedQuotaLabel = '';
    c.quotaSearch        = '';
    c.quotaDisplayText   = '';
    c.filteredQuotas     = c.data.quotas || [];
    c.quotaDropOpen      = false;

    c.userConditions    = [{ field: '', operator: 'contains', value: '', logic: 'AND' }];
    c.userFilterApplied = false;
    c.filteredUsers     = c.data.users || [];

    if (c.data.users) {
      c.data.users.forEach(function(u) {
        u.selected = false;
      });
    }
  };

  /* ================= USER SELECTION ================= */


	c.filterAvailableOnly = function() {
  c.selectAll = false; // reset checkbox

  var allUsers = c.data.users || [];
  var base = c.userFilterApplied ? c.filteredUsers : allUsers;

  if (c.showAvailableOnly) {
    c.filteredUsers = base.filter(function(u) {
      return !u.disabled;
    });
  } else {
    c.filteredUsers = c.userFilterApplied ? base : allUsers;
  }
};

	c.updateSelectAllState = function() {
  var all = c.filteredUsers.filter(u => !u.disabled);
  var selected = all.filter(u => u.selected);

  c.selectAll = all.length && all.length === selected.length;
};


  c.getSelectedCount = function() {
    if (!c.data.users) return 0;
    return c.data.users.filter(function(u) {
      return u.selected;
    }).length;
  };

 c.toggleSelectAll = function() {
  if (!c.filteredUsers) return;

  var allSelected = c.filteredUsers.every(function(u) {
    return u.disabled || u.selected;
  });

  c.filteredUsers.forEach(function(u) {
    if (!u.disabled) {
      u.selected = !allSelected;
    }
  });
};

  /* ================= ASSIGN QUOTA ================= */

  c.assignQuota = function() {
    if (!c.selectedQuota) {
      spUtil.addErrorMessage("Please select a quota");
      return;
    }

    var selectedUsers = (c.data.users || []).filter(function(u) {
      return u.selected;
    });

    if (!selectedUsers.length) {
      spUtil.addErrorMessage("Please select at least one user");
      return;
    }

    var payload = {
      action: 'assignQuota',
      data: {
        quota: c.selectedQuota,
        users: selectedUsers.map(function(u) {
          return u.sys_id;
        })
      }
    };

    c.loading = true;

    c.server.get(payload).then(function(response) {
      c.loading = false;

      if (response.data && response.data.status === "success") {
        spUtil.addInfoMessage("Quota assigned successfully");
        c.goBack();

        c.server.update().then(function() {
          c.filtered = c.data.rows || [];

        });
      } else {
        spUtil.addErrorMessage("Assignment failed. Try again.");
      }
    });
  };

	c.unassignQuotaUser = function(user) {

  spModal.open({
    title: "Confirm Unassign",
    message: "Are you sure you want to unassign " + user.name + " from quota?",
    buttons: [
      { label: "Cancel", cancel: true },
      { label: "Unassign", primary: true }
    ]
  }).then(function() {

    c.server.get({
      action: "unassignQuotaUser",
      userId: user.sys_id
    }).then(function(response) {

      if (response.data && response.data.status === "success") {

        spUtil.addInfoMessage(user.name + " unassigned successfully");

        //  reload users only (same pattern as before)
        c.reloadUsers();

      } else {
        spUtil.addErrorMessage("Failed to unassign user");
      }

    });

  });
};
	c.reloadUsers = function() {

  c.server.get({
    action: "getUsers"
  }).then(function(response) {

    c.data.users = response.data.users;

    if (c.userFilterApplied) {
      c.runUserFilter();
    } else {
      c.filteredUsers = c.data.users;
    }

  });
};


  /* ================= INIT LOAD ================= */

  c.$onInit = function() {
  c.filtered       = c.data.rows   || [];
  c.filteredQuotas = c.data.quotas || [];
  c.filteredUsers  = c.data.users  || [];

  /*  AUTO SELECT QUOTA FROM URL */
  if (c.data.sys_id) {

    var match = null;

    for (var i = 0; i < c.filteredQuotas.length; i++) {
      if (c.filteredQuotas[i].sys_id == c.data.sys_id) {
        match = c.filteredQuotas[i];
        break;
      }
    }

    if (match) {
      c.pickQuota(match);
    }
  }
};

};

sp_widget.css:
.error-box {
      background: #fff;
      border-left: 6px solid #e53935;
      padding: 0.5rem 1.2rem;
      border-radius: 8px;
      box-shadow: 0 4px 10px rgba(0,0,0,0.1);
      display: flex;
      align-items: center;
      gap: 12px;
    }

    .error-icon {
      font-size: 24px;
      color: #e53935;
    }

    .error-text {
      color: #333;
      font-size: 16px;
      font-weight: 500;
    }



.qa-user-disabled {
  opacity: 0.5;
}

.qa-user-disabled .qa-user-name {
  color: #777 !important;
}

.qa-user-disabled .qa-user-email {
  color: #9ca3af !important;
}

.qa-user-disabled .qa-segment-label {
  background: #f1f5f9 !important;
  color: #9ca3af !important;
}

.assignement-page {
	background: #f1f5f9;
  padding: 2.8rem 3.2rem;
  font-family: "Segoe UI", -apple-system, BlinkMacSystemFont, sans-serif;
}

.qa-user-disabled .qa-unassign-btn {
  opacity: 1 !important;
  color: #dc2626 !important;
}

.qa-unassign-btn {
  font-size: 12px;
  color: #dc2626;
  font-weight: 600;
  padding: 4px 6px;
}



.qa-unassign-btn:hover {
  text-decoration: underline;
  color: #b91c1c;
}


/* ================= GLOBAL ================= */

.admin-main {
  padding: 10px 15px;
  background: #f5f7fb;
}

/* ================= HEADER ================= */

.admin-main h2 {
  font-weight: 600;
  color: #111827;
}

.admin-main p {
  color: #6b7280;
}

/* ================= FILTER BAR ================= */

.quota-filter-row {
  background: #f1f5f9;
  padding: 16px 18px;
  border-radius: 14px;
  margin-bottom: 25px;
}

.quota-filter-row .col-sm-3 {
  display: flex;
  align-items: center;
}

.quota-filter-row select,
.quota-filter-row input {
  border-radius: 12px;
  height: 40px;
  border: 1px solid #e5e7eb;
  background: #fff;
  transition: all 0.2s ease;
}

.quota-filter-row select:focus,
.quota-filter-row input:focus {
  border-color: #2563eb;
  box-shadow: 0 0 0 2px rgba(37,99,235,0.1);
}

/* ================= KPI CARDS ================= */

.quota-kpi-card {
  border-radius: 18px;
  border: 1px solid #e6e8ec;
  background: linear-gradient(180deg, #ffffff, #f9fafb);
  transition: all 0.25s ease;
}

.quota-kpi-card .panel-body {
  padding: 22px;
}

.quota-kpi-card p {
  margin: 0;
  font-size: 13px;
  color: #6b7280;
}

.quota-kpi-card h2 {
  font-size: 28px;
  font-weight: 600;
  margin: 8px 0;
  color: #111827;
}

.quota-kpi-card small {
  color: #9ca3af;
}

.quota-kpi-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 12px 30px rgba(0,0,0,0.1);
}

/* ================= TOGGLE BUTTON ================= */

.btn-group {
  background: #eef2f7;
  padding: 4px;
  border-radius: 12px;
}

.btn-group .btn {
  border-radius: 10px !important;
  padding: 6px 16px;
  border: none;
  background: transparent;
}

.btn-group .btn.active {
  background: #2563eb;
  color: white;
  box-shadow: 0 4px 12px rgba(37,99,235,0.3);
}

/* ================= QUOTA CARDS ================= */

.quota-card {
  border-radius: 18px;
  border: 1px solid #e5e7eb;
  background: linear-gradient(180deg, #ffffff, #f9fafb);
  padding: 18px;
  transition: all 0.3s ease;
  margin-bottom: 20px;
}

.quota-card:hover {
  transform: translateY(-6px);
  box-shadow: 0 14px 35px rgba(0,0,0,0.12);
}

/* TITLE */

.quota-title {
  font-size: 16px;
  font-weight: 600;
  color: #111827;
}

/* SUBTEXT */

.quota-desc {
  font-size: 12px;
  color: #6b7280;
  margin-bottom: 12px;
}

/* META INFO */

.quota-meta {
  font-size: 12px;
  color: #4b5563;
  margin-bottom: 10px;
}

.quota-meta div {
  margin-bottom: 5px;
}

/* VALUE */

.quota-value {
  font-size: 20px;
  font-weight: 600;
  color: #111827;
  margin-bottom: 12px;
}

/* BADGE */

.quota-badge {
  display: inline-block;
  background: linear-gradient(90deg, #e0f2fe, #bae6fd);
  color: #0369a1;
  font-size: 11px;
  padding: 6px 12px;
  border-radius: 12px;
  text-transform: capitalize;
}

/* ================= TABLE ================= */

/* CARD WRAPPER */

.panel.quota-card {
  padding: 0;
}

/* HEADER */

.panel-heading {
  padding: 14px 18px;
  border-bottom: 1px solid #e5e7eb;
  background: transparent;
}

.panel-title {
  font-weight: 600;
  color: #111827;
}

/* TABLE BASE */

.table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 0;
}

/* FORCE GRID LINES */

.table,
.table th,
.table td {
  border: 1px solid #e5e7eb !important;
}

/* HEADER */

.table thead th {
  background: #f3f4f6;
  font-weight: 600;
  color: #374151;
  padding: 12px;
}

/* ROWS */

.table tbody td {
  padding: 12px;
  color: #374151;
}

/* ALTERNATE ROW */

.table tbody tr:nth-child(even) {
  background: #fafafa;
}

/* HOVER */

.table tbody tr:hover {
  background: #f1f5f9;
}

/* ================= BUTTON ================= */

.btn-success {
  border-radius: 10px;
  padding: 8px 16px;
  background: #22c55e;
  border: none;
}

.btn-success:hover {
  background: #16a34a;
}

/* ================= RESPONSIVE ================= */

@media (max-width: 768px) {
  .quota-kpi-card h2 {
    font-size: 22px;
  }
  .quota-value {
    font-size: 18px;
  }
}

/* =================================================================
   ASSIGN QUOTA INLINE PAGE STYLES
================================================================= */

/* Top bar with back button */

.qa-page-topbar {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 1px solid #e2e8f0;
}

.qa-back-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: #ffffff;
  border: 1.5px solid #e2e8f0;
  cursor: pointer;
  color: #374151;
  transition: background 0.15s, border-color 0.15s;
  flex-shrink: 0;
}

.qa-back-btn:hover {
  background: #f1f5f9;
  border-color: #94a3b8;
}

.qa-page-topbar-title {
  font-size: 2.4rem;
  font-weight: 700;
  color: #111827;
}

/* Form card */

.qa-form-page {
  background: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 16px;
  box-shadow: 0 1px 4px rgba(0,0,0,0.06);
  overflow: hidden;
}

.qa-form-page-heading {
  font-size: 18px;
  font-weight: 700;
  color: #111827;
  padding: 24px 28px 4px;
}

.qa-form-page-sub {
  font-size: 13px;
  color: #6b7280;
  padding: 0 28px 20px;
  border-bottom: 1px solid #f1f5f9;
}

.qa-form-body {
  padding: 24px 28px;
}

/* Quota select inside form page */

.qa-select {
  border-radius: 10px !important;
  height: 42px;
  border: 1px solid #e5e7eb !important;
  transition: all 0.2s ease;
  color: #111827 !important;
  background-color: #ffffff !important;
  font-weight: 500;
}

.qa-select option {
  color: #111827;
  font-weight: 400;
}

.qa-select option[value=""] {
  color: #9ca3af;
}

.qa-select:focus {
  border-color: #2563eb !important;
  box-shadow: 0 0 0 2px rgba(37,99,235,0.1) !important;
}

/* Select All row */

.qa-select-all-row {
  margin-bottom: 12px;
  display: flex;
}

.qa-checkbox-label {
  display: flex;
  align-items: center;
  gap: 8px;
  font-weight: 500;
  color: #374151;
  cursor: pointer;
  margin: 0;
}

.qa-checkbox {
  margin: 0 !important;
  cursor: pointer;
}

/* User list container */

.qa-user-list {
  max-height: 340px;
  overflow-y: auto;
  border: 1px solid #e5e7eb;
  border-radius: 12px;
  margin-bottom: 12px;
}

.qa-user-list::-webkit-scrollbar {
  width: 5px;
}

.qa-user-list::-webkit-scrollbar-thumb {
  background: #cbd5e1;
  border-radius: 10px;
}

/* Individual user row */

.qa-user-row {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 13px 16px;
  border-bottom: 1px solid #f1f1f1;
  transition: background 0.12s;
}

.qa-user-row:last-child {
  border-bottom: none;
}

.qa-user-row:hover {
  background: #f8fafc;
}

.qa-user-info {
  flex: 1;
}

.qa-user-name {
  font-weight: 600;
  font-size: 14px;
  color: #111827;
}

.qa-user-email {
  font-size: 12px;
  color: #6b7280;
  margin-top: 2px;
}

.qa-segment-label {
  font-size: 11px;
  padding: 3px 8px;
  border-radius: 8px;
  background: #f1f5f9;
  color: #475569;
  white-space: nowrap;
  flex-shrink: 0;
}

/* Count text */

.qa-count-text {
  font-size: 13px;
  color: #6b7280;
  margin-top: 8px;
  margin-bottom: 0;
}

/* Footer */

.qa-form-footer {
  display: flex;
  justify-content: flex-end;
  align-items: center;
  gap: 10px;
  padding: 16px 28px 24px;
  border-top: 1px solid #f1f5f9;
}

.qa-btn-cancel {
  border-radius: 10px !important;
  padding: 8px 18px !important;
}

.qa-btn-assign {
  border-radius: 10px !important;
  padding: 8px 20px !important;
}

/* Required star */

.qa-req {
  color: #ef4444;
}

/* ================= QUOTA COMBINED SEARCH + SELECT ================= */

.qa-quota-search-wrap {
  margin-bottom: 20px;
  position: relative;
}

.qa-quota-search-box {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 9px 12px;
  border: 1.5px solid #e5e7eb;
  border-radius: 10px;
  background: #f8fafc;
  transition: border-color 0.2s, box-shadow 0.2s;
  cursor: text;
}

.qa-quota-box-open {
  border-color: #6b7280 !important;
  background: #ffffff !important;
  border-bottom-left-radius: 0 !important;
  border-bottom-right-radius: 0 !important;
}

.qa-quota-search-box:focus-within {
  border-color: #6b7280;
  background: #ffffff;
}

.qa-quota-search-icon {
  color: #9ca3af;
  flex-shrink: 0;
}

.qa-quota-search-input {
  flex: 1;
  border: none;
  outline: none;
  background: transparent;
  font-size: 13px;
  color: #111827;
  font-weight: 500;
  font-family: inherit;
  min-width: 0;
}

.qa-quota-search-input::placeholder {
  color: #9ca3af;
  font-weight: 400;
}

.qa-quota-search-clear {
  display: flex;
  align-items: center;
  justify-content: center;
  background: none;
  border: none;
  cursor: pointer;
  color: #9ca3af;
  padding: 2px;
  border-radius: 4px;
  flex-shrink: 0;
  transition: color 0.15s, background 0.15s;
}

.qa-quota-search-clear:hover {
  color: #374151;
  background: #e5e7eb;
}

.qa-quota-dropdown {
  position: absolute;
  top: 100%;
  left: 0;
  right: 0;
  z-index: 999;
  background: #ffffff;
  border: 1.5px solid #6b7280;
  border-top: none;
  border-bottom-left-radius: 10px;
  border-bottom-right-radius: 10px;
  box-shadow: 0 6px 18px rgba(0,0,0,0.09);
  max-height: 260px;
  overflow-y: auto;
}

.qa-quota-dropdown::-webkit-scrollbar {
  width: 5px;
}

.qa-quota-dropdown::-webkit-scrollbar-thumb {
  background: #cbd5e1;
  border-radius: 10px;
}

.qa-quota-dropdown-empty {
  padding: 14px 16px;
  font-size: 13px;
  color: #9ca3af;
}

.qa-quota-option {
  display: flex;
  align-items: center;
  padding: 10px 16px;
  gap: 10px;
  cursor: pointer;
  border-bottom: 1px solid #f8fafc;
  transition: background 0.1s;
}

.qa-quota-option:last-child {
  border-bottom: none;
}

.qa-quota-option:hover {
  background: #f1f5f9;
}

.qa-quota-option-selected {
  background: #f0f6ff;
}

.qa-quota-opt-name {
  font-size: 14px;
  font-weight: 600;
  color: #111827;
  flex: 1;
}

.qa-quota-opt-meta {
  font-size: 12px;
  color: #6b7280;
  white-space: nowrap;
}

.qa-quota-opt-check {
  color: #2563eb;
  flex-shrink: 0;
}

/* ================= USER FILTER — SN-style custom filter UI ================= */

.qa-uf-wrap {
  border: 1px solid #d1d5db;
  border-radius: 10px;
  background: #f3f4f6;
  margin-bottom: 16px;
  overflow: hidden;
}

.qa-uf-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px;
  background: #e5e7eb;
  border-bottom: 1px solid #d1d5db;
}

.qa-uf-toolbar-label {
  font-size: 12px;
  font-weight: 600;
  color: #374151;
}

.qa-uf-toolbar-right {
  display: flex;
  gap: 6px;
}

.qa-uf-btn {
  background: #ffffff;
  border: 1px solid #d1d5db;
  border-radius: 5px;
  font-size: 12px;
  color: #374151;
  padding: 4px 12px;
  cursor: pointer;
  font-family: inherit;
  transition: background 0.15s;
}

.qa-uf-btn:hover {
  background: #f9fafb;
}

.qa-uf-btn-run {
  background: #2563eb;
  color: #ffffff;
  border-color: #2563eb;
}

.qa-uf-btn-run:hover {
  background: #1d4ed8;
}

.qa-uf-conditions {
  padding: 10px 12px;
}

.qa-uf-condition-header {
  font-size: 11px;
  color: #6b7280;
  margin-bottom: 8px;
}

.qa-uf-condition-row {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 8px;
  flex-wrap: wrap;
}

.qa-uf-cond-field,
.qa-uf-cond-op {
  height: 32px;
  border: 1px solid #d1d5db;
  border-radius: 5px;
  background: #ffffff;
  font-size: 12px;
  color: #111827;
  padding: 0 6px;
}

.qa-uf-cond-field {
  min-width: 150px;
}

.qa-uf-cond-op {
  min-width: 110px;
}

.qa-uf-cond-val {
  flex: 1;
  min-width: 160px;
  height: 32px;
  border: 1px solid #d1d5db;
  border-radius: 5px;
  background: #ffffff;
  font-size: 12px;
  color: #111827;
  padding: 0 8px;
  font-family: inherit;
}

.qa-uf-cond-val:focus,
.qa-uf-cond-field:focus,
.qa-uf-cond-op:focus {
  outline: none;
  border-color: #2563eb;
  box-shadow: 0 0 0 2px rgba(37,99,235,0.1);
}

.qa-uf-cond-remove {
  display: flex;
  align-items: center;
  justify-content: center;
  background: none;
  border: none;
  cursor: pointer;
  color: #9ca3af;
  padding: 4px;
  border-radius: 4px;
  transition: color 0.15s;
}

.qa-uf-cond-remove:hover {
  color: #dc2626;
}

.qa-uf-logic-pills {
  display: flex;
  gap: 3px;
}

.qa-uf-pill {
  padding: 2px 8px;
  border-radius: 4px;
  border: 1px solid #d1d5db;
  background: #ffffff;
  font-size: 11px;
  font-weight: 600;
  color: #6b7280;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}

.qa-uf-pill-active {
  background: #fef9c3;
  border-color: #ca8a04;
  color: #854d0e;
}

.qa-uf-add-row {
  padding: 4px 12px 10px;
}

.qa-uf-result {
  padding: 8px 12px;
  font-size: 12px;
  color: #6b7280;
  background: #ffffff;
  border-top: 1px solid #e5e7eb;
}

.qa-uf-noresult {
  color: #ef4444;
}

sp_widget.script:
(function() {

  data  = data  || {};
  input = input || {};

	data.sys_id = $sp.getParameter('sys_id');
	data.isIncentNowGroupAdmin= gs.hasRole('x_ctans_incentnow.business_group_admin')|| gs.hasRole('x_ctans_incentnow.admin');


  var OPT = options || {};

  /* ---- Table names ---- */
  var QUOTA_TABLE      = OPT.quota_table      || 'x_ctans_incentnow_quota';
  var USER_TABLE       = OPT.user_table       || 'x_ctans_incentnow_user_profile';
  var ASSIGN_TABLE     = OPT.assignment_table || 'x_ctans_incentnow_user_quota_assignment';

  /* ---- Quota field names ---- */
  var Q_NAME   = OPT.quota_name_field  || 'name';
  var Q_BU     = OPT.quota_bu_field    || 'business_unit';
  var Q_FY     = OPT.quota_fy_field    || 'fiscal_year';
  var Q_FREQ   = OPT.quota_freq_field  || 'quota_frequency';
  var Q_VALUE  = OPT.quota_value_field || 'target_value';
  var Q_ROLE   = OPT.quota_role_field  || 'role';

  /* ---- User field names ---- */
  var U_NAME   = OPT.user_name_field   || 'name';
  var U_EMAIL  = OPT.user_email_field  || 'email';
  var U_BU     = OPT.user_bu_field     || 'business_unit';
  var U_ROLE   = OPT.user_role_field   || 'role';

  /* ---- Assignment field names ---- */
  var A_USER   = OPT.assign_user_field  || 'user';
  var A_QUOTA  = OPT.assign_quota_field || 'quota';
  var A_ROLE   = OPT.assign_role_field  || 'role';
  var A_BU     = OPT.assign_bu_field    || 'business_unit';

  /* ================= ASSIGN QUOTA ACTION ================= */

  if (input.action === 'assignQuota') {

    var quotaId = input.data && input.data.quota;
    var users   = (input.data && input.data.users) || [];

    if (!quotaId || users.length === 0) {
      data.status = "error";
      return;
    }

    var quotaGR = new GlideRecordSecure(QUOTA_TABLE);

    if (!quotaGR.get(quotaId)) {
      data.status = "error";
      return;
    }

    var role = quotaGR.getValue(Q_ROLE) || '';

    users.forEach(function(userId) {
      if (!userId) return;

      var userGR       = new GlideRecordSecure(USER_TABLE);
      var businessUnit = '';

      if (userGR.get(userId)) {
        businessUnit = userGR.getValue(U_BU) || '';
      }

      var check = new GlideRecordSecure(ASSIGN_TABLE);
      check.addQuery(A_USER,  userId);
      check.addQuery(A_QUOTA, quotaId);
      check.setLimit(1);
      check.query();

      if (!check.hasNext()) {
        var grAssign = new GlideRecordSecure(ASSIGN_TABLE);
        grAssign.initialize();
        grAssign.setValue(A_USER,  userId);
        grAssign.setValue(A_QUOTA, quotaId);
        grAssign.setValue(A_ROLE,  role);
        grAssign.setValue(A_BU,    businessUnit);
        grAssign.insert();
      }
    });

    data.status = "success";
    return;
  }

  /* ================= LOAD ASSIGNMENTS ================= */

  data.rows      = [];
  var totalQuota = 0;
  var buSet      = {};
  var years      = {};

  var userMap   = {};
  var userGRMap = new GlideRecordSecure(USER_TABLE);
  userGRMap.query();

  while (userGRMap.next()) {
    userMap[userGRMap.getUniqueValue()] = {
      //name:         userGRMap.user.name.toString() || '',
      businessUnit: userGRMap.getDisplayValue(U_BU)   || ''
    };
  }

  var grTab = new GlideRecordSecure(ASSIGN_TABLE);
  grTab.query();

  while (grTab.next()) {

    var quotaGR = new GlideRecordSecure(QUOTA_TABLE);
    if (!quotaGR.get(grTab.getValue(A_QUOTA))) continue;

    var raw    = quotaGR.getValue(Q_VALUE);
    var target = (!raw || isNaN(parseFloat(raw))) ? 0 : parseFloat(raw);

    var userId   = grTab.getValue(A_USER);
    var userData = userMap[userId] || {};

    var businessUnit = userData.businessUnit || '';
    var userName     = userData.name         || '';
    var fiscalYear   = quotaGR.getDisplayValue(Q_FY)   || '';
    var frequency    = quotaGR.getValue(Q_FREQ)         || '';

    var row = {
      user:               userName,
      quota:              quotaGR.getValue(Q_NAME) || '',
      businessUnit:       businessUnit,
      financialYear:      fiscalYear,
      targetValue:        target,
      targetDisplay:      (target / 1000).toFixed(0),
      distributionMethod: frequency
    };

    data.rows.push(row);
    totalQuota += target;

    if (businessUnit) buSet[businessUnit] = true;
    if (fiscalYear)   years[fiscalYear]   = true;
  }

  data.businessUnits  = Object.keys(buSet);
  data.financialYears = Object.keys(years);

  data.summary = {
    total:         data.rows.length,
    totalQuota:    (totalQuota / 1000).toFixed(0),
    avgQuota:      data.rows.length
                     ? (totalQuota / data.rows.length / 1000).toFixed(0)
                     : 0,
    businessUnits: Object.keys(buSet).length
  };



/* ================= GET ALREADY ASSIGNED USERS ================= */

var assignedMap = {};

var relGR = new GlideRecordSecure(ASSIGN_TABLE);
relGR.addEncodedQuery("quota.status!=inactive");
	//quota.status!=inactive
relGR.query();

while (relGR.next()) {

    var userId = relGR.getValue(A_USER);   // should be 'user'
    var quotaName = relGR.getDisplayValue(A_QUOTA); // should be 'quota'

    if (userId) {
        assignedMap[userId + ""] = quotaName || "Assigned";
    }
}


  /* ================= LOAD USERS ================= */

	data.planBU = '';

		if (data.sys_id) {
				var qGR = new GlideRecordSecure(QUOTA_TABLE);
				if (qGR.get(data.sys_id)) {
						data.planBU = qGR.getValue('business_unit') || '';
				}
		}

getUsers();
function getUsers()
	{
	data.users     = [];
  var segmentSet = {};
  var roleSet    = {};

  var userGR = new GlideRecordSecure(USER_TABLE);
  userGR.addQuery('active', true);
	if (data.planBU) {
    		userGR.addQuery('business_unit', data.planBU);
				}
  userGR.query();
		//gs.addErrorMessage(userGR.getEncodedQuery());

  while (userGR.next()) {
    var uSegment = userGR.getDisplayValue(U_BU)   || '';
    var uRole    = userGR.getValue(U_ROLE)         || '';

   var userId = userGR.getUniqueValue();
		var assignedQuota = assignedMap[userId + ""];  //  string match fix

		data.users.push({
			sys_id: userId,
			name: userGR.user.name.toString()  || '',
			email: userGR.user.email.toString() || '',
			segment: uSegment,
			role: uRole,
			selected: false,

			disabled: assignedQuota ? true : false,   //  explicit
			quota: assignedQuota || '',
			tooltip: assignedQuota ? ('Assigned to: ' + assignedQuota) : ''
		});

    if (uSegment) segmentSet[uSegment] = true;
    if (uRole)    roleSet[uRole]       = true;
  }

  data.userSegments = Object.keys(segmentSet).sort();
  data.userRoles    = Object.keys(roleSet).sort();
	}


	if (input.action === "unassignQuotaUser") {

    var userId = input.userId;
    var removed = false;

    var grUser = new GlideRecordSecure(ASSIGN_TABLE);
    grUser.addQuery(A_USER, userId);
    grUser.query();

    while (grUser.next()) {
        grUser.deleteRecord();
        removed = true;
    }

    data.status = removed ? "success" : "error";
    return;
}



  /* ================= LOAD QUOTAS ================= */

  data.quotas = [];

  var quotaGR2 = new GlideRecordSecure(QUOTA_TABLE);
  quotaGR2.orderBy(Q_NAME);
  quotaGR2.query();

  while (quotaGR2.next()) {
    var rawQ    = quotaGR2.getValue(Q_VALUE);
    var targetQ = (!rawQ || isNaN(parseFloat(rawQ))) ? 0 : parseFloat(rawQ);

    data.quotas.push({
      sys_id:        quotaGR2.getUniqueValue(),
      name:          quotaGR2.getValue(Q_NAME)           || '',
      business_unit: quotaGR2.getDisplayValue(Q_BU)      || '',
      financial_year: quotaGR2.getDisplayValue(Q_FY)     || '',
      target:        targetQ
    });
  }

	if(input.action==='getUsers')
		{
			getUsers();
		}

	/*if (input.action === "getUsers") {

    data.users = [];
    var segmentSet = {};
    var roleSet = {};
    var assignedMap = {};

    var relGR = new GlideRecordSecure(ASSIGN_TABLE);
    relGR.query();

    while (relGR.next()) {
        var userId = relGR.getValue(A_USER);
        var quotaName = relGR.getDisplayValue(A_QUOTA);

        if (userId) {
            assignedMap[userId + ""] = quotaName || "Assigned";
        }
    }

    var userGR = new GlideRecordSecure(USER_TABLE);
    userGR.addQuery('active', true);
    userGR.query();

    while (userGR.next()) {

        var userId = userGR.getUniqueValue();
        var segment = userGR.getDisplayValue(U_BU) || '';
        var role = userGR.getValue(U_ROLE) || '';
        var assignedQuota = assignedMap[userId + ""];

        data.users.push({
            sys_id: userId,
            name: userGR.getValue(U_NAME) || '',
            email: userGR.getValue(U_EMAIL) || '',
            segment: segment,
            role: role,
            selected: false,
            disabled: assignedQuota ? true : false,
            quota: assignedQuota || '',
            tooltip: assignedQuota ? ('Assigned to: ' + assignedQuota) : ''
        });

        if (segment) segmentSet[segment] = true;
        if (role) roleSet[role] = true;
    }

    data.userSegments = Object.keys(segmentSet).sort();
    data.userRoles = Object.keys(roleSet).sort();

    return;
} */

})();
